import{_ as i,o as a,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const p=JSON.parse('{"title":"Dubbo学习","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/13-Dubbo学习/13-Dubbo学习.md","filePath":"语言/java/13-Dubbo学习/13-Dubbo学习.md","lastUpdated":1777177198000}'),o={name:"语言/java/13-Dubbo学习/13-Dubbo学习.md"};function h(b,l,n,d,t,s){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="dubbo学习" tabindex="-1">Dubbo学习 <a class="header-anchor" href="#dubbo学习" aria-label="Permalink to “Dubbo学习”">​</a></h1><p>Dubbo 是 Java 生态里非常典型的一类 RPC 框架。<br> 但学习 Dubbo，真正难的往往不是“把 demo 跑起来”，而是把下面这些问题串成一张完整的图：</p><ul><li>服务是怎么暴露出去的</li><li>Consumer 是怎么找到 Provider 的</li><li>多个实例时请求怎么选目标节点</li><li>失败后为什么有的请求要重试，有的不能重试</li><li>为什么线上还需要路由、限流、降级、配置中心</li><li>为什么一个“超时”背后可能是线程池、网络、SQL、重试共同造成的</li></ul><p>所以这一组内容的目标，不是让你只会配几个注解，而是让你真正建立起：</p><blockquote><p><strong>Dubbo = 远程调用框架 + 服务治理能力 + 线上排障思维</strong></p></blockquote><h2 id="专题目录" tabindex="-1">专题目录 <a class="header-anchor" href="#专题目录" aria-label="Permalink to “专题目录”">​</a></h2><ul><li><a href="./01-基础架构与调用链路.html">01-基础架构与调用链路</a></li><li><a href="./02-服务暴露与服务发现.html">02-服务暴露与服务发现</a></li><li><a href="./03-负载均衡与容错机制.html">03-负载均衡与容错机制</a></li><li><a href="./04-序列化与通信协议.html">04-序列化与通信协议</a></li><li><a href="./05-治理能力与配置中心.html">05-治理能力与配置中心</a></li><li><a href="./06-性能调优与排障.html">06-性能调优与排障</a></li></ul><h2 id="_1-学习定位" tabindex="-1">1. 学习定位 <a class="header-anchor" href="#_1-学习定位" aria-label="Permalink to “1. 学习定位”">​</a></h2><p>这一组内容面向的是：</p><ul><li>已经学过 Java 基础和网络基础</li><li>想进入服务化、分布式调用、微服务治理方向</li><li>不满足于“会写注解配置”，想搞懂调用链路和线上问题的人</li></ul><p>学习完这一组，你至少应该形成三层理解：</p><h3 id="第一层-知道-dubbo-在干什么" tabindex="-1">第一层：知道 Dubbo 在干什么 <a class="header-anchor" href="#第一层-知道-dubbo-在干什么" aria-label="Permalink to “第一层：知道 Dubbo 在干什么”">​</a></h3><p>也就是：</p><ul><li>它让 Java 服务之间做远程调用更方便</li><li>它把复杂的网络调用包装成更接近本地接口的体验</li></ul><h3 id="第二层-知道一次调用到底怎么走" tabindex="-1">第二层：知道一次调用到底怎么走 <a class="header-anchor" href="#第二层-知道一次调用到底怎么走" aria-label="Permalink to “第二层：知道一次调用到底怎么走”">​</a></h3><p>也就是：</p><ul><li>Provider 怎么暴露</li><li>Consumer 怎么发现</li><li>请求怎么选路</li><li>数据怎么编码传输</li><li>错误怎么处理</li></ul><h3 id="第三层-知道线上为什么还需要治理与排障" tabindex="-1">第三层：知道线上为什么还需要治理与排障 <a class="header-anchor" href="#第三层-知道线上为什么还需要治理与排障" aria-label="Permalink to “第三层：知道线上为什么还需要治理与排障”">​</a></h3><p>也就是：</p><ul><li>服务不是“跑起来就结束”</li><li>真正难的是稳定运行、动态调整、快速定位故障</li></ul><h2 id="_2-这一组到底在学什么" tabindex="-1">2. 这一组到底在学什么 <a class="header-anchor" href="#_2-这一组到底在学什么" aria-label="Permalink to “2. 这一组到底在学什么”">​</a></h2><p>可以把 Dubbo 的知识分成 6 个连续的问题：</p><h3 id="_2-1-它的整体架构是什么" tabindex="-1">2.1 它的整体架构是什么 <a class="header-anchor" href="#_2-1-它的整体架构是什么" aria-label="Permalink to “2.1 它的整体架构是什么”">​</a></h3><p>先搞清楚：</p><ul><li>Consumer</li><li>Provider</li><li>Registry</li><li>Proxy</li><li>Protocol</li></ul><p>分别做什么。</p><h3 id="_2-2-服务怎么上线并被别人找到" tabindex="-1">2.2 服务怎么上线并被别人找到 <a class="header-anchor" href="#_2-2-服务怎么上线并被别人找到" aria-label="Permalink to “2.2 服务怎么上线并被别人找到”">​</a></h3><p>也就是：</p><ul><li>服务暴露</li><li>服务注册</li><li>服务发现</li><li>地址变更通知</li></ul><h3 id="_2-3-多个服务实例时-请求怎么选、失败了怎么办" tabindex="-1">2.3 多个服务实例时，请求怎么选、失败了怎么办 <a class="header-anchor" href="#_2-3-多个服务实例时-请求怎么选、失败了怎么办" aria-label="Permalink to “2.3 多个服务实例时，请求怎么选、失败了怎么办”">​</a></h3><p>也就是：</p><ul><li>负载均衡</li><li>容错策略</li><li>超时与重试</li></ul><h3 id="_2-4-一次远程调用的数据是怎么传的" tabindex="-1">2.4 一次远程调用的数据是怎么传的 <a class="header-anchor" href="#_2-4-一次远程调用的数据是怎么传的" aria-label="Permalink to “2.4 一次远程调用的数据是怎么传的”">​</a></h3><p>也就是：</p><ul><li>序列化</li><li>协议头</li><li>请求响应模型</li><li>编解码与兼容性</li></ul><h3 id="_2-5-服务多起来后-线上怎么控" tabindex="-1">2.5 服务多起来后，线上怎么控 <a class="header-anchor" href="#_2-5-服务多起来后-线上怎么控" aria-label="Permalink to “2.5 服务多起来后，线上怎么控”">​</a></h3><p>也就是：</p><ul><li>动态配置</li><li>路由</li><li>限流</li><li>降级</li><li>黑白名单</li></ul><h3 id="_2-6-线上慢了、炸了、超时了怎么查" tabindex="-1">2.6 线上慢了、炸了、超时了怎么查 <a class="header-anchor" href="#_2-6-线上慢了、炸了、超时了怎么查" aria-label="Permalink to “2.6 线上慢了、炸了、超时了怎么查”">​</a></h3><p>也就是：</p><ul><li>性能调优</li><li>链路排障</li><li>重试放大</li><li>线程池积压</li><li>下游慢点识别</li></ul><p>把这 6 个问题串起来，你对 Dubbo 的理解就不是碎片化的了。</p><h2 id="_3-学习重点" tabindex="-1">3. 学习重点 <a class="header-anchor" href="#_3-学习重点" aria-label="Permalink to “3. 学习重点”">​</a></h2><p>这一组最核心的学习重点有 5 个：</p><ul><li>理解 Dubbo 的调用链路和角色分工</li><li>理解注册中心在服务体系里的作用</li><li>理解负载均衡和容错为什么直接影响可用性</li><li>理解协议和序列化为什么影响性能与兼容性</li><li>理解治理和排障为什么是生产环境的关键能力</li></ul><p>你会发现，这 5 个重点其实对应的是：</p><ul><li><strong>能不能调通</strong></li><li><strong>能不能调稳</strong></li><li><strong>出问题能不能快速看明白</strong></li></ul><h2 id="_4-建议顺序" tabindex="-1">4. 建议顺序 <a class="header-anchor" href="#_4-建议顺序" aria-label="Permalink to “4. 建议顺序”">​</a></h2><p>建议按下面顺序学，不容易乱：</p><ol><li>基础架构与调用链路</li><li>服务暴露与服务发现</li><li>负载均衡与容错机制</li><li>序列化与通信协议</li><li>治理能力与配置中心</li><li>性能调优与排障</li></ol><p>这个顺序的原因很简单：</p><ul><li>先看全局图</li><li>再看服务怎么连起来</li><li>再看运行时怎么做选择和兜底</li><li>再看底层通信</li><li>再看线上控制能力</li><li>最后再看出现问题时怎么排</li></ul><p>如果一上来先学调优和排障，很容易只记住一堆故障名词，但不知道它们卡在链路哪一层。</p><h2 id="_5-学这一组时最容易踩的坑" tabindex="-1">5. 学这一组时最容易踩的坑 <a class="header-anchor" href="#_5-学这一组时最容易踩的坑" aria-label="Permalink to “5. 学这一组时最容易踩的坑”">​</a></h2><h3 id="_5-1-只会照着-demo-配-不理解链路" tabindex="-1">5.1 只会照着 demo 配，不理解链路 <a class="header-anchor" href="#_5-1-只会照着-demo-配-不理解链路" aria-label="Permalink to “5.1 只会照着 demo 配，不理解链路”">​</a></h3><p>这样一旦遇到：</p><ul><li>注册失败</li><li>调用超时</li><li>版本不匹配</li><li>重试放大</li></ul><p>就很难定位。</p><h3 id="_5-2-把-dubbo-误解成-就是另一个-http" tabindex="-1">5.2 把 Dubbo 误解成“就是另一个 HTTP” <a class="header-anchor" href="#_5-2-把-dubbo-误解成-就是另一个-http" aria-label="Permalink to “5.2 把 Dubbo 误解成“就是另一个 HTTP””">​</a></h3><p>Dubbo 和 HTTP 都能做服务调用，但关注点不同。</p><p>Dubbo 更强调：</p><ul><li>Java 服务间 RPC</li><li>注册发现</li><li>集群容错</li><li>服务治理</li></ul><h3 id="_5-3-只重视-能调用-不重视-能运营" tabindex="-1">5.3 只重视“能调用”，不重视“能运营” <a class="header-anchor" href="#_5-3-只重视-能调用-不重视-能运营" aria-label="Permalink to “5.3 只重视“能调用”，不重视“能运营””">​</a></h3><p>服务真正上线后，治理能力和排障能力往往比“首个调用跑通”更重要。</p><h3 id="_5-4-一看到错误就直接改参数" tabindex="-1">5.4 一看到错误就直接改参数 <a class="header-anchor" href="#_5-4-一看到错误就直接改参数" aria-label="Permalink to “5.4 一看到错误就直接改参数”">​</a></h3><p>例如：</p><ul><li>调大超时</li><li>增加重试</li></ul><p>这有时不但解决不了问题，反而会放大问题。</p><h2 id="_6-学完后你应该能做到什么" tabindex="-1">6. 学完后你应该能做到什么 <a class="header-anchor" href="#_6-学完后你应该能做到什么" aria-label="Permalink to “6. 学完后你应该能做到什么”">​</a></h2><p>学完这一组后，理想状态下你应该能做到：</p><ul><li>画出一张 Dubbo 基础调用链路图</li><li>解释 Provider、Consumer、Registry 分别做什么</li><li>说清楚服务暴露和服务发现的区别</li><li>区分负载均衡和容错策略解决的不是同一个问题</li><li>解释一次 RPC 调用为什么离不开协议和序列化</li><li>说出治理能力为什么能让系统更稳</li><li>遇到 Dubbo 超时问题时，知道先从哪几个维度排查</li></ul><h2 id="_7-阶段产出" tabindex="-1">7. 阶段产出 <a class="header-anchor" href="#_7-阶段产出" aria-label="Permalink to “7. 阶段产出”">​</a></h2><p>建议你在学完这一组后，至少整理出 3 份东西：</p><ul><li>一份 Dubbo 调用链路图</li><li>一份服务治理能力清单</li><li>一份 RPC 性能与排障笔记</li></ul><p>如果你能把这三份东西整理出来，说明你已经不是“只看过文章”，而是开始形成自己的结构化理解了。</p><h2 id="_8-动手建议" tabindex="-1">8. 动手建议 <a class="header-anchor" href="#_8-动手建议" aria-label="Permalink to “8. 动手建议”">​</a></h2><p>学这一组时，不建议只看概念。</p><p>最起码可以做 3 类小实验：</p><h3 id="_8-1-跑通最小-provider-consumer" tabindex="-1">8.1 跑通最小 Provider / Consumer <a class="header-anchor" href="#_8-1-跑通最小-provider-consumer" aria-label="Permalink to “8.1 跑通最小 Provider / Consumer”">​</a></h3><p>目标：</p><ul><li>感受一次最小 RPC 调用链</li></ul><h3 id="_8-2-故意制造一个失败场景" tabindex="-1">8.2 故意制造一个失败场景 <a class="header-anchor" href="#_8-2-故意制造一个失败场景" aria-label="Permalink to “8.2 故意制造一个失败场景”">​</a></h3><p>例如：</p><ul><li>Provider 停掉</li><li>注册中心地址配错</li><li>版本号不一致</li></ul><p>目标：</p><ul><li>感受调用失败会表现成什么样</li></ul><h3 id="_8-3-故意制造一个慢场景" tabindex="-1">8.3 故意制造一个慢场景 <a class="header-anchor" href="#_8-3-故意制造一个慢场景" aria-label="Permalink to “8.3 故意制造一个慢场景”">​</a></h3><p>例如：</p><ul><li>Provider 加 <code>Thread.sleep</code></li><li>Consumer 开启重试</li></ul><p>目标：</p><ul><li>理解超时、重试、线程池为什么会互相放大问题</li></ul><h2 id="_9-自测标准" tabindex="-1">9. 自测标准 <a class="header-anchor" href="#_9-自测标准" aria-label="Permalink to “9. 自测标准”">​</a></h2><p>学完这组内容，你至少要能回答这些问题：</p><ul><li>Dubbo 为什么是 RPC 框架，而不只是简单 HTTP 调用？</li><li>注册中心、负载均衡、容错分别解决什么问题？</li><li>为什么远程调用必须重视协议与兼容性？</li><li>为什么服务上线后还需要治理能力，而不是只靠代码配置？</li><li>为什么一个 Dubbo 超时问题常常不是单点问题？</li></ul><h2 id="_10-这一组你至少要带走什么" tabindex="-1">10. 这一组你至少要带走什么 <a class="header-anchor" href="#_10-这一组你至少要带走什么" aria-label="Permalink to “10. 这一组你至少要带走什么”">​</a></h2><p>如果你看完这一组只记住 5 件事，就记这 5 件：</p><ol><li><strong>Dubbo 的核心不是注解，而是完整的 RPC 调用链路</strong></li><li><strong>注册发现、负载均衡、容错、协议、治理是一套连在一起的系统</strong></li><li><strong>“能调通”只是开始，“能稳定运行”才是重点</strong></li><li><strong>线上服务需要治理能力，不然只能靠发版硬调</strong></li><li><strong>排障要按链路拆问题，不能只盯着表面报错</strong></li></ol><p>带着这套地图去看后面的 6 篇文章，你会更容易把 Dubbo 学成一个整体。</p>',98)])])}const c=i(o,[["render",h]]);export{p as __pageData,c as default};
